   250→        var payload = new
   251→        {
   252→            generatedAt = report.GeneratedAt.ToString("O"),
   253→            warningWindowDays = report.WarningWindowDays,
   254→            summary = new
   255→            {
   256→                total = report.Results.Count,
   257→                expired = report.Expired.Count,
   258→                warning = report.Warning.Count,
   259→                ok = report.Ok.Count
   260→            },
   261→            expired = report.Expired.Select(ToEntry).ToArray(),
   262→            warning = report.Warning.Select(ToEntry).ToArray(),
   263→            ok      = report.Ok.Select(ToEntry).ToArray()
   264→        };
   265→
   266→        return JsonSerializer.Serialize(payload, JsonOptions);
   267→    }
   268→
   269→    private static object ToEntry(RotationResult r) => new
   270→    {
   271→        name = r.Secret.Name,
   272→        lastRotated = r.Secret.LastRotated.ToString("yyyy-MM-dd"),
   273→        rotationPolicyDays = r.Secret.RotationPolicyDays,
   274→        requiredByServices = r.Secret.RequiredByServices,
   275→        daysUntilExpiry = r.DaysUntilExpiry,
   276→        status = r.Status,
   277→        message = r.Message
   278→    };
   279→}
