     1→// Output formatters for the rotation report.
     2→// Supports markdown table and JSON formats.
     3→// Both are pure functions: given a RotationReport, return a string.
     4→
     5→using System.Text;
     6→using System.Text.Json;
     7→using System.Text.Json.Serialization;
     8→
     9→namespace SecretRotation;
    10→
    11→public static class ReportFormatter
    12→{
    13→    // ─────────────────────────────────────────────────────────
    14→    // Markdown table format
    15→    // ─────────────────────────────────────────────────────────
    16→
    17→    /// <summary>
    18→    /// Renders the rotation report as a markdown document with grouped tables.
    19→    /// </summary>
    20→    public static string ToMarkdown(RotationReport report)
    21→    {
    22→        var sb = new StringBuilder();
    23→
    24→        sb.AppendLine("# Secret Rotation Report");
    25→        sb.AppendLine();
    26→        sb.AppendLine($"**Generated:** {report.GeneratedAt:yyyy-MM-dd HH:mm:ss} UTC  ");
    27→        sb.AppendLine($"**Warning window:** {report.WarningWindowDays} days  ");
    28→        sb.AppendLine($"**Total secrets:** {report.Results.Count}  ");
    29→        sb.AppendLine();
    30→
    31→        // Summary counts
    32→        sb.AppendLine("## Summary");
    33→        sb.AppendLine();
    34→        sb.AppendLine($"| Status  | Count |");
    35→        sb.AppendLine($"|---------|-------|");
    36→        sb.AppendLine($"| 🔴 Expired | {report.Expired.Count} |");
    37→        sb.AppendLine($"| 🟡 Warning | {report.Warning.Count} |");
    38→        sb.AppendLine($"| 🟢 OK      | {report.Ok.Count} |");
    39→        sb.AppendLine();
    40→
    41→        // Per-status sections
    42→        AppendSection(sb, "🔴 Expired", report.Expired, "Expired");
    43→        AppendSection(sb, "🟡 Warning", report.Warning, "Warning");
    44→        AppendSection(sb, "🟢 OK", report.Ok, "OK");
    45→
    46→        return sb.ToString();
    47→    }
    48→
    49→    private static void AppendSection(
    50→        StringBuilder sb,
    51→        string heading,
    52→        IReadOnlyList<RotationResult> results,
    53→        string statusLabel)
    54→    {
    55→        sb.AppendLine($"## {heading}");
    56→        sb.AppendLine();
    57→
    58→        if (results.Count == 0)
    59→        {
    60→            sb.AppendLine($"_No secrets in {statusLabel} state._");
    61→            sb.AppendLine();
    62→            return;
    63→        }
    64→
    65→        // Markdown table header
    66→        sb.AppendLine("| Secret Name | Policy (days) | Days Until Expiry | Required By | Message |");
    67→        sb.AppendLine("|-------------|--------------|-------------------|-------------|---------|");
    68→
    69→        foreach (var r in results)
    70→        {
    71→            var services = string.Join(", ", r.Secret.RequiredByServices);
    72→            sb.AppendLine(
    73→                $"| {r.Secret.Name} " +
    74→                $"| {r.Secret.RotationPolicyDays} " +
    75→                $"| {r.DaysUntilExpiry} " +
    76→                $"| {services} " +
    77→                $"| {r.Message} |");
    78→        }
    79→
    80→        sb.AppendLine();
    81→    }
    82→
    83→    // ─────────────────────────────────────────────────────────
    84→    // JSON format
    85→    // ─────────────────────────────────────────────────────────
    86→
    87→    private static readonly JsonSerializerOptions JsonOptions = new()
    88→    {
    89→        WriteIndented = true,
    90→        // Serialize enums as strings ("Expired") not integers (0)
    91→        Converters = { new JsonStringEnumConverter() }
    92→    };
    93→
    94→    /// <summary>
    95→    /// Renders the rotation report as a structured JSON document.
    96→    /// Results are grouped into "expired", "warning", and "ok" arrays.
    97→    /// </summary>
    98→    public static string ToJson(RotationReport report)
    99→    {
   100→        var payload = new
   101→        {
   102→            generatedAt = report.GeneratedAt.ToString("O"),          // ISO 8601
   103→            warningWindowDays = report.WarningWindowDays,
   104→            summary = new
   105→            {
   106→                total = report.Results.Count,
   107→                expired = report.Expired.Count,
   108→                warning = report.Warning.Count,
   109→                ok = report.Ok.Count
   110→            },
   111→            expired = report.Expired.Select(ToJsonEntry).ToArray(),
   112→            warning = report.Warning.Select(ToJsonEntry).ToArray(),
   113→            ok      = report.Ok.Select(ToJsonEntry).ToArray()
   114→        };
   115→
   116→        return JsonSerializer.Serialize(payload, JsonOptions);
